import React, { useEffect, useState } from "react";
import JournalCard from "./JournalCard";
import axios from 'axios'

const History = ({ onEditEntry }) => {
  const [entries, setEntries] = useState([]);

  useEffect(() => {
    const getJournals = async () => {
      const addingEntry = await axios.get('/api/journal/getAllJournals/687e7cd167ec0a24dc89bc80',
        {
          headers: {
            'Authorization': "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjY4N2U3Y2QxNjdlYzBhMjRkYzg5YmM4MCIsImVtYWlsIjoiYWRtaW5AZ21haWwuY29tIiwiaWF0IjoxNzUzNDYzNDA5fQ.14586A4q0MW-2AGKFmbTIM3lRcAzxgslQzgJHWOTFTQ"
          }
        })
      setEntries(addingEntry.data.journals);
    }
    getJournals();
  }, [entries]);
  
  // useEffect(() => {
  //   const stored = JSON.parse(localStorage.getItem("journalEntries")) || [];
  //   setEntries(stored.reverse());
  // }, []);

  const handleDelete = (id) => {
    if (window.confirm("Are you sure you want to delete this entry?")) {
      // const stored = JSON.parse(localStorage.getItem("journalEntries")) || [];
      const stored=entries;
      const filtered = stored.filter((e) => e.id !== id);
      localStorage.setItem("journalEntries", JSON.stringify(filtered));
      setEntries(filtered.reverse());
    }
  };

  return (
    <div className="history-page">
      <h1 className="history-heading">Journal History</h1>
      <div className="history-list">
        {entries.length > 0 ? (
          entries.map((entry) => (
            <JournalCard
              key={entry._id}
              id={entry._id}
              title={entry.title}
              date={entry.date}
              entry={entry.journalNote}
              // analyzed={entry.analyzed}
              // analysis={entry.analysis}
              // onEdit={onEditEntry}
              // onDelete={handleDelete}
            />
          ))
        ) : (
          <p>No journal entries found.</p>
        )}
      </div>
      <Stylesheet />
    </div>
  );
};

const Stylesheet = () => {
  return <style>{`
        .history-page {
          font-family: 'Cedarville Cursive', cursive;
          color: var(--text);
          padding: 1rem;
          display: flex;
          flex-direction: column;
          align-items: center;
        }

        .history-heading {
          font-size: 2.5rem;
          margin-bottom: 2rem;
        }

        .history-list {
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          gap: 1rem;
          width: 100%;
          max-width: 1200px;
        }

        @media (max-width: 600px) {
          .history-heading {
            font-size: 2rem;
          }
        }
      `}</style>
}
export default History;
